+/// Compute statistics from a vector of durations.
+pub fn compute_statistics(durations: &[u128], rss_values: &[Option<u64>]) -> RunStatistics {
+    let n = durations.len();
+    if n == 0 {
+        return RunStatistics {
+            min_ms: 0,
+            max_ms: 0,
+            median_ms: 0,
+            mean_ms: 0.0,
+            stddev_ms: 0.0,
+            cv: 0.0,
+            median_rss_bytes: None,
+        };
+    }
+
+    // Sort for min/max/median
+    let mut sorted = durations.to_vec();
+    sorted.sort();
+
+    let min_ms = sorted[0];
+    let max_ms = sorted[n - 1];
+    let median_ms = if n % 2 == 0 {
+        (sorted[n / 2 - 1] + sorted[n / 2]) / 2
+    } else {
+        sorted[n / 2]
+    };
+
+    // Mean
+    let sum: u128 = sorted.iter().sum();
+    let mean_ms = sum as f64 / n as f64;
+
+    // Standard deviation
+    let variance: f64 = sorted.iter()
+        .map(|&x| {
+            let diff = x as f64 - mean_ms;
+            diff * diff
+        })
+        .sum::<f64>() / n as f64;
+    let stddev_ms = variance.sqrt();
+
+    // Coefficient of variation
+    let cv = if mean_ms > 0.0 { stddev_ms / mean_ms } else { 0.0 };
+
+    // Median RSS
+    let median_rss_bytes = {
+        let mut rss_vals: Vec<u64> = rss_values.iter().filter_map(|&v| v).collect();
+        if rss_vals.is_empty() {
+            None
+        } else {
+            rss_vals.sort();
+            let rn = rss_vals.len();
+            Some(if rn % 2 == 0 {
+                (rss_vals[rn / 2 - 1] + rss_vals[rn / 2]) / 2
+            } else {
+                rss_vals[rn / 2]
+            })
+        }
+    };
+
+    RunStatistics {
+        min_ms,
+        max_ms,
+        median_ms,
+        mean_ms,
+        stddev_ms,
+        cv,
+        median_rss_bytes,
+    }
+}
